// Build screen scenes
const container = document.getElementById('screen-scenes');
screenSceneData.forEach((s, i) => {
  const el = document.createElement('div');
  el.className = 'scene scene-screen';
  el.id = 's' + (i + 2);
  el.innerHTML = `
    <div class="screen-left">
      <div class="screen-tag">${s.tag}</div>
      <div class="screen-title">${s.title}</div>
      <div class="screen-desc">${s.desc}</div>
    </div>
    <div class="screen-right">
      <div class="screen-frame">
        <img src="${IMGS[s.imgIdx]}" alt="${s.title}" loading="lazy">
        <div class="screen-glow"></div>
      </div>
    </div>
  `;
  container.appendChild(el);
});

const TOTAL = 15;
const DURATION = 5500;
let current = 0;
let playing = true;
let timer = null;
let progressTimer = null;
let progressStart = null;

const labels = [
  'INTRO', 'FRAGMENTED SPACE',
  'ONBOARDING','SECURITY','PATIENTS','DASHBOARD','DOCTORS',
  'SCHEDULING','BOOKING','CONTEXT','MANAGEMENT','CONFIRMATION',
  'BILLING','TELEMEDICINE','CLOSING'
];

// Build dots
const dotsEl = document.getElementById('dots');
for (let i = 0; i < TOTAL; i++) {
  const d = document.createElement('div');
  d.className = 'dot';
  d.onclick = () => goTo(i);
  dotsEl.appendChild(d);
}

function showScene(idx) {
  document.querySelectorAll('.scene').forEach((el, i) => {
    el.classList.remove('active', 'exit');
    if (i < idx) el.classList.add('exit');
  });
  const target = document.getElementById('s' + idx);
  if (target) target.classList.add('active');
  document.querySelectorAll('.dot').forEach((d, i) => {
    d.classList.toggle('active', i === idx);
  });
  document.getElementById('scene-counter').textContent = (idx + 1) + ' / ' + TOTAL;
  document.getElementById('scene-label').textContent = labels[idx] || '';
  current = idx;
}

function goTo(idx) {
  clearTimers();
  showScene(idx);
  if (playing) scheduleNext();
}

function nextScene() {
  const next = (current + 1) % TOTAL;
  clearTimers();
  showScene(next);
  if (playing) scheduleNext();
}

function prevScene() {
  const prev = (current - 1 + TOTAL) % TOTAL;
  clearTimers();
  showScene(prev);
  if (playing) scheduleNext();
}

function scheduleNext() {
  progressStart = Date.now();
  animateProgress();
  timer = setTimeout(nextScene, DURATION);
}

function animateProgress() {
  const fill = document.getElementById('progress-fill');
  const pct = (current / TOTAL) * 100;
  const segW = 100 / TOTAL;

  function tick() {
    if (!playing) return;
    const elapsed = Date.now() - progressStart;
    const segPct = Math.min(elapsed / DURATION, 1) * segW;
    fill.style.width = (pct + segPct) + '%';
    if (elapsed < DURATION) progressTimer = requestAnimationFrame(tick);
  }
  cancelAnimationFrame(progressTimer);
  tick();
}

function clearTimers() {
  clearTimeout(timer);
  cancelAnimationFrame(progressTimer);
}

function togglePlay() {
  playing = !playing;
  document.getElementById('playBtn').textContent = playing ? '⏸ Pause' : '▶ Play';
  if (playing) scheduleNext();
  else clearTimers();
}

// Init
showScene(0);
scheduleNext();
